pub fn to_thread(state: &LuaState, idx: i32) -> Option<GcRef<lua_types::value::LuaThread>> {
    // C: return (!ttisthread(o)) ? NULL : thvalue(o);
    // TODO(phase-b): lua-vm's rich LuaState is not the same type as
